// Find the 3rd largest element
vector<int> numbers = {3, 2, 1, 5, 6, 4};
int k = 2;
// sorted descending: 6, 5, 4, 3, 2, 1 — the 2nd largest is 5

#include <iostream>
#include <vector>
#include <queue>

using namespace std;

int findKthLargest(vector<int> &numbers, int k)
{
    priority_queue<int, vector<int>, greater<int>> minHeap; // recall greater<int> from Custom Comparators

    for (int n : numbers)
    {
        minHeap.push(n);
        if (minHeap.size() > k)
        {
            minHeap.pop(); // discard the current smallest — it can't be in the top k
        }
    }
    return minHeap.top();
}

int main()
{
    vector<int> numbers = {3, 2, 1, 5, 6, 4};

    cout << findKthLargest(numbers, 2) << endl;

    return 0;
}

