#include <iostream>
#include <vector>
#include <unordered_map>
#include <algorithm>

using namespace std;

vector<int> topKFrequent(vector<int> &nums, int k)
{
    unordered_map<int, int> counts;
    for (int n : nums) counts[n]++;

    vector<pair<int,int>> freqList; // (count, value)
    for (auto &[val, cnt] : counts) freqList.push_back({cnt, val});

    sort(freqList.begin(), freqList.end(), greater<pair<int,int>>());

    vector<int> result;
    for (int i = 0; i < k; i++) result.push_back(freqList[i].second);

    return result;
}

int main()
{
    vector<int> nums = {1, 1, 1, 2, 2, 3};

    vector<int> result = topKFrequent(nums, 2);
    for (int r : result) cout << r << " ";

    return 0;
}

