#include <queue>

using namespace std;

vector<vector<int>> kClosest(vector<vector<int>> &points, int k)
{
    auto dist = [](vector<int> &p) { return p[0]*p[0] + p[1]*p[1]; };

    priority_queue<pair<int, vector<int>>> maxHeap; // default max-heap, ordered by squared distance

    for (auto &p : points)
    {
        maxHeap.push({dist(p), p});
        if ((int)maxHeap.size() > k) maxHeap.pop();
    }

    vector<vector<int>> result;
    while (!maxHeap.empty())
    {
        result.push_back(maxHeap.top().second);
        maxHeap.pop();
    }

    return result;
}

int main()
{
    vector<vector<int>> points = {{1, 3}, {-2, 2}};

    auto result = kClosest(points, 1);
    for (auto &p : result) cout << "[" << p[0] << "," << p[1] << "] ";

