class MedianFinder {
public:
    vector<int> nums;

    void addNum(int num)
    {
        nums.insert(upper_bound(nums.begin(), nums.end(), num), num);
    }

    double findMedian()
    {
        int n = nums.size();
        if (n % 2 == 1) return nums[n / 2];
        return (nums[n / 2 - 1] + nums[n / 2]) / 2.0;
    }
};

int main()
{
    MedianFinder mf;
    mf.addNum(1); mf.addNum(2);
    cout << mf.findMedian() << " ";
    mf.addNum(3);
    cout << mf.findMedian() << endl;

    return 0;
}

#include <iostream>
#include <queue>

using namespace std;

class MedianFinder {
public:
    priority_queue<int> lower; // max-heap
    priority_queue<int, vector<int>, greater<int>> upper; // min-heap

    void addNum(int num)
    {
        if (lower.empty() || num <= lower.top()) lower.push(num);
        else upper.push(num);

        if (lower.size() > upper.size() + 1)
        {
            upper.push(lower.top());
            lower.pop();
        }
        else if (upper.size() > lower.size())
        {
            lower.push(upper.top());
            upper.pop();
        }
    }

    double findMedian()
    {
        if (lower.size() > upper.size()) return lower.top();
        return (lower.top() + upper.top()) / 2.0;
    }
};

int main()
{
    MedianFinder mf;
    mf.addNum(1); mf.addNum(2);
    cout << mf.findMedian() << " ";
    mf.addNum(3);
    cout << mf.findMedian() << endl;

    return 0;
}

